    public showMessageModal(params: { title: string, message: string, duration: number }) {
        if (!this.showMessageModalDom) {
            console.warn('Show message modal element not found');
            return;
        }

        // 清理之前的处理器和定时器
        this.cleanupShowMessageModalHandlers();
        if (this.showMessageModalTimeout) {
            clearTimeout(this.showMessageModalTimeout);
            this.showMessageModalTimeout = null;
        }

        const titleElement = this.showMessageModalDom.querySelector('#modelShowMessageLabel');
        const messageElement = this.showMessageModalDom.querySelector('#modelShowMessageMessage');
        const confirmButton = this.showMessageModalDom.querySelector('[data-role="confirm"]');
        const closeButton = this.showMessageModalDom.querySelector('.btn-close');

        if (titleElement) {
            (titleElement as HTMLElement).textContent = params.title;
        }
        if (messageElement) {
            (messageElement as HTMLElement).textContent = params.message;
        }

        // 设置确认按钮事件处理器
        if (confirmButton && this.showMessageModalConfirmHandler) {
            confirmButton.removeEventListener('click', this.showMessageModalConfirmHandler);
        }
        this.showMessageModalConfirmHandler = () => {
            this.closeShowMessageModal();
        };
        if (confirmButton) {
            confirmButton.addEventListener('click', this.showMessageModalConfirmHandler);
        }

        // 设置关闭按钮事件处理器
        if (closeButton && this.showMessageModalCloseHandler) {
            closeButton.removeEventListener('click', this.showMessageModalCloseHandler);
        }
        this.showMessageModalCloseHandler = () => {
            this.closeShowMessageModal();
        };
        if (closeButton) {
            closeButton.addEventListener('click', this.showMessageModalCloseHandler);
        }

        // 设置隐藏事件处理器
        if (this.showMessageModalDom) {
            if (this.showMessageModalHiddenHandler) {
                this.showMessageModalDom.removeEventListener('hidden.bs.modal', this.showMessageModalHiddenHandler as EventListener);
            }
            this.showMessageModalHiddenHandler = () => {
                this.cleanupShowMessageModalHandlers();
            };
            this.showMessageModalDom.addEventListener('hidden.bs.modal', this.showMessageModalHiddenHandler as EventListener);
        }

        // 初始化 Bootstrap Modal 实例
        if (!this.showMessageModalInstance && typeof bootstrap !== 'undefined' && bootstrap && typeof bootstrap.Modal === 'function') {
            this.showMessageModalInstance = new bootstrap.Modal(this.showMessageModalDom);
        }

        // 显示模态框
        if (this.showMessageModalInstance && typeof this.showMessageModalInstance.show === 'function') {
            this.showMessageModalInstance.show();
        } else {
            this.showMessageModalDom.classList.add('show', 'vision-modal-show');
            this.showMessageModalDom.style.display = 'block';
        }

        // 如果 duration > 0，设置自动关闭定时器
        if (params.duration > 0) {
            this.showMessageModalTimeout = setTimeout(() => {
                this.closeShowMessageModal();
            }, 1000 * params.duration);
        }
    }
    public closeConfirmDialog() {
        if (!this.confirmModalDom) {
            return;
        }

        if (this.confirmModalInstance && typeof this.confirmModalInstance.hide === 'function') {
            this.confirmModalInstance.hide();
        } else {
            this.confirmModalDom.classList.remove('show', 'vision-modal-show');
            this.confirmModalDom.style.display = 'none';
        }

        this.cleanupConfirmDialogHandlers();
    }
    public closeShowMessageModal() {
        if (!this.showMessageModalDom) {
            return;
        }

        // 清除自动关闭定时器
        if (this.showMessageModalTimeout) {
            clearTimeout(this.showMessageModalTimeout);
            this.showMessageModalTimeout = null;
        }

        // 使用 Bootstrap Modal 关闭
        if (this.showMessageModalInstance && typeof this.showMessageModalInstance.hide === 'function') {
            this.showMessageModalInstance.hide();
        } else {
            this.showMessageModalDom.classList.remove('show', 'vision-modal-show');
            this.showMessageModalDom.style.display = 'none';
        }

        // 清理事件处理器
        this.cleanupShowMessageModalHandlers();
    }

    private cleanupConfirmDialogHandlers() {
        if (!this.confirmModalDom) {
            this.confirmCancelHandler = null;
            this.confirmConfirmHandler = null;
            this.confirmCloseHandler = null;
            this.confirmHiddenHandler = null;
            this.confirmOnCancel = null;
            this.confirmLastAction = 'dismiss';
            return;
        }

        const cancelButton = this.confirmModalDom.querySelector('[data-role="cancel"]');
        const confirmButton = this.confirmModalDom.querySelector('[data-role="confirm"]');
        const closeButton = this.confirmModalDom.querySelector('.btn-close');

        if (cancelButton && this.confirmCancelHandler) {
            cancelButton.removeEventListener('click', this.confirmCancelHandler);
        }
        if (confirmButton && this.confirmConfirmHandler) {
            confirmButton.removeEventListener('click', this.confirmConfirmHandler);
        }
        if (closeButton && this.confirmCloseHandler) {
            closeButton.removeEventListener('click', this.confirmCloseHandler);
        }
        if (this.confirmHiddenHandler) {
            this.confirmModalDom.removeEventListener('hidden.bs.modal', this.confirmHiddenHandler as EventListener);
        }

        this.confirmCancelHandler = null;
        this.confirmConfirmHandler = null;
        this.confirmCloseHandler = null;
        this.confirmHiddenHandler = null;
        this.confirmOnCancel = null;
        this.confirmLastAction = 'dismiss';
    }

    private cleanupShowMessageModalHandlers() {
        if (!this.showMessageModalDom) {
            this.showMessageModalConfirmHandler = null;
            this.showMessageModalCloseHandler = null;
            this.showMessageModalHiddenHandler = null;
            return;
        }

        const confirmButton = this.showMessageModalDom.querySelector('[data-role="confirm"]');
        const closeButton = this.showMessageModalDom.querySelector('.btn-close');

        if (confirmButton && this.showMessageModalConfirmHandler) {
            confirmButton.removeEventListener('click', this.showMessageModalConfirmHandler);
        }
        if (closeButton && this.showMessageModalCloseHandler) {
            closeButton.removeEventListener('click', this.showMessageModalCloseHandler);
        }
        if (this.showMessageModalHiddenHandler) {
            this.showMessageModalDom.removeEventListener('hidden.bs.modal', this.showMessageModalHiddenHandler as EventListener);
        }

        this.showMessageModalConfirmHandler = null;
        this.showMessageModalCloseHandler = null;
        this.showMessageModalHiddenHandler = null;
    }

