/**
 * Clone a File object
 * @param file - The file to be cloned
 * @returns A new File object with the same content, name and type
 */
export async function cloneFile(file: File): Promise<File> {
    if (!(file instanceof File)) {
        throw new Error('Parameter must be a File object');
    }

    const arrayBuffer = await file.arrayBuffer();
    return new File([arrayBuffer], file.name, {
        type: file.type,
        lastModified: file.lastModified
    });
}

